def format_primes(data, filename="primes_list.txt"):
    # .split() handles tabs, spaces, and newlines automatically
    primes = data.split()
    
    # Write them to the file separated by \n
    with open(filename, "w") as f:
        f.write("\n".join(primes) + "\n")
    
    print(f"Successfully formatted {len(primes)} large primes into {filename}.")

if __name__ == "__main__":
    # You can paste your full string into raw_data or read it from a messy file
    format_primes(raw_data)
